import{_ as e,H as t,o as r,c as i,J as a,C as o,V as c}from"./chunks/framework.729ad155.js";const P=JSON.parse('{"title":"浙江象山 XiangShan √","description":"","frontmatter":{"title":"浙江象山 XiangShan √"},"headers":[],"relativePath":"views/travel/domestic/ZjXs.md","filePath":"views/travel/domestic/ZjXs.md"}'),s={name:"views/travel/domestic/ZjXs.md"},g=o("p",null,"我爸妈开车来宁波接我去象山玩，因为6.20是我的生日，算是陪我过个生日吧，很感动。",-1),h=c('<h3 id="_2016-06-18-☁️-😁" tabindex="-1">2016.06.18 ☁️ 😁 <a class="header-anchor" href="#_2016-06-18-☁️-😁" aria-label="Permalink to &quot;2016.06.18 ☁️ 😁&quot;">​</a></h3><p>从宁波出发前往象山，第一站来到的就是象山影视城 <br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/2.JPG" width="300"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/4.JPG" width="300"> <br> 👇路过一个蛮好看的花果山。<br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/7.JPG?imageMogr2/auto-orient" width="300"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/8.JPG?imageMogr2/auto-orient" width="300"> <br> 👇带我妹妹玩一个冰屋，外面貌似有剧组在拍戏。<br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/9.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/11.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/10.JPG?imageMogr2/auto-orient" width="270"> <br> 👇貌似是琅琊榜的拍摄取景地，反正我没看过。<br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/14.JPG?imageMogr2/auto-orient" width="270"> <br> 👇下午去了象山古城。<br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/15.JPG?imageMogr2/auto-orient" width="270"> <br> 👇傍晚的时候开车路过了一座大桥，真的蛮好看的。<br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/16.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/17.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/18.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/19.JPG?imageMogr2/auto-orient" width="270"><br></p><h3 id="_2016-06-19-☁️-😁" tabindex="-1">2016.06.19 ☁️ 😁 <a class="header-anchor" href="#_2016-06-19-☁️-😁" aria-label="Permalink to &quot;2016.06.19 ☁️ 😁&quot;">​</a></h3><p>第二天我爸联系了一个当地渔民，讨价还价把我们拉到了一个外海岛上，貌似海还是依旧黄，不过比沿海要好太多了。第一次坐渔船也是很新奇！<br><img src="http://cdn.chenyingshuang.cn/journey/zjxs/21.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/22.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/25.JPG?imageMogr2/auto-orient" width="270"><img src="http://cdn.chenyingshuang.cn/journey/zjxs/27.JPG?imageMogr2/auto-orient" width="270"><br> 玩完就回去上学啦，这个生日过的很不平凡！~</p>',4);function u(d,m,j,p,y,_){const n=t("common-ImageWall");return r(),i("div",null,[g,a(n,{value:"journey/zjxs/",number:27,imgType:"JPG"}),h])}const x=e(s,[["render",u]]);export{P as __pageData,x as default};
